/// Sanitizer that removes sensitive data from log entries
class LogSanitizer {
  /// Redact sensitive fields from a Map
  static Map<String, dynamic> sanitizeMap(Map<String, dynamic>? data) {
    if (data == null) return {};

    final sanitized = <String, dynamic>{};
    for (final entry in data.entries) {
      final keyLower = entry.key.toLowerCase();
      if (_isSensitiveField(keyLower)) {
        sanitized[entry.key] = '[REDACTED]';
      } else if (entry.value is Map<String, dynamic>) {
        sanitized[entry.key] =
            sanitizeMap(entry.value as Map<String, dynamic>);
      } else if (entry.value is List) {
        sanitized[entry.key] = _sanitizeList(entry.value as List);
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  /// Redact sensitive headers
  static Map<String, String> sanitizeHeaders(Map<String, String>? headers) {
    if (headers == null) return {};

    final sanitized = <String, String>{};
    for (final entry in headers.entries) {
      final keyLower = entry.key.toLowerCase();
      if (_isSensitiveHeader(keyLower)) {
        sanitized[entry.key] = '[REDACTED]';
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  /// Sanitize a URL by removing query parameters that contain sensitive data
  static String sanitizeUrl(String url) {
    try {
      final uri = Uri.parse(url);
      if (uri.queryParameters.isEmpty) return url;

      final sanitizedParams = <String, String>{};
      for (final entry in uri.queryParameters.entries) {
        final keyLower = entry.key.toLowerCase();
        if (_isSensitiveField(keyLower)) {
          sanitizedParams[entry.key] = '[REDACTED]';
        } else {
          sanitizedParams[entry.key] = entry.value;
        }
      }

      return uri.replace(queryParameters: sanitizedParams).toString();
    } catch (_) {
      return '[INVALID_URL]';
    }
  }

  /// Sanitize request/response body
  static String sanitizeBody(dynamic body) {
    if (body == null) return '[empty]';

    try {
      if (body is String) {
        // Try to parse as JSON and sanitize
        try {
          final parsed = jsonDecode(body);
          if (parsed is Map<String, dynamic>) {
            return jsonEncode(sanitizeMap(parsed));
          }
          return body;
        } catch (_) {
          // Not JSON, check for sensitive patterns in form data
          return _sanitizeFormData(body);
        }
      } else if (body is Map<String, dynamic>) {
        return jsonEncode(sanitizeMap(body));
      }
      return '[binary data - ${body.toString().length} bytes]';
    } catch (_) {
      return '[unserializable body]';
    }
  }

  /// Sanitize user identifiers - keep partial info for debugging
  static String sanitizeEmail(String? email) {
    if (email == null || email.isEmpty) return '[no email]';
    final parts = email.split('@');
    if (parts.length != 2) return '[invalid email]';
    final localPart = parts[0];
    final domain = parts[1];
    if (localPart.length <= 2) {
      return '**@$domain';
    }
    return '${localPart[0]}***${localPart[localPart.length - 1]}@$domain';
  }

  /// Sanitize user ID - keep partial for correlation
  static String sanitizeUserId(String? userId) {
    if (userId == null || userId.isEmpty) return '[no user id]';
    if (userId.length <= 4) return '****';
    return '${userId.substring(0, 4)}****';
  }

  static bool _isSensitiveField(String fieldName) {
    return LogConfig.sensitiveFields.any(
      (sensitive) => fieldName.contains(sensitive),
    );
  }

  static bool _isSensitiveHeader(String headerName) {
    return LogConfig.sensitiveHeaders.any(
      (sensitive) => headerName.contains(sensitive),
    );
  }

  static List _sanitizeList(List items) {
    return items.map((item) {
      if (item is Map<String, dynamic>) {
        return sanitizeMap(item);
      } else if (item is List) {
        return _sanitizeList(item);
      }
      return item;
    }).toList();
  }

  static String _sanitizeFormData(String body) {
    // Handle URL-encoded form data like "password=secret&username=user"
    if (body.contains('=')) {
      final parts = body.split('&');
      final sanitized = parts.map((part) {
        final keyValue = part.split('=');
        if (keyValue.length == 2) {
          final keyLower = keyValue[0].toLowerCase();
          if (_isSensitiveField(keyLower)) {
            return '${keyValue[0]}=[REDACTED]';
          }
        }
        return part;
      }).join('&');
      return sanitized;
    }
    return body;
  }
}

/// Structured log entry
class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final String category;
  final String message;
  final Map<String, dynamic>? metadata;
  final String? correlationId;

  LogEntry({
    required this.level,
    required this.category,
    required this.message,
    this.metadata,
    this.correlationId,
  }) : timestamp = DateTime.now().toUtc();

  Map<String, dynamic> toJson() {
    return {
      'timestamp': timestamp.toIso8601String(),
      'level': level.name,
      'category': category,
      'message': _truncateMessage(message),
      if (metadata != null) 'metadata': metadata,
      if (correlationId != null) 'correlationId': correlationId,
    };
  }

  String _truncateMessage(String msg) {
    if (msg.length > LogConfig.maxLogEntrySize) {
      return '${msg.substring(0, LogConfig.maxLogEntrySize)}... [TRUNCATED]';
    }
    return msg;
  }

  @override
  String toString() {
    final buffer = StringBuffer();
    buffer.write('[${timestamp.toIso8601String()}]');
    buffer.write('[${level.name.toUpperCase()}]');
    buffer.write('[$category]');
    if (correlationId != null) {
      buffer.write('[cid:$correlationId]');
    }
    buffer.write(' $message');
    return buffer.toString();
  }
}

/// Main application logger - secure by default
class AppLogger {
  static final AppLogger _instance = AppLogger._internal();
  factory AppLogger() => _instance;
  AppLogger._internal();

  final List<LogSink> _sinks = [];
  String? _currentCorrelationId;

  /// Initialize the logger with appropriate sinks
  void initialize({List<LogSink>? sinks}) {
    _sinks.clear();

    if (kDebugMode) {
      // In debug mode, log to console with sanitization still applied
      _sinks.add(ConsoleLogSink());
    }

    if (sinks != null) {
      _sinks.addAll(sinks);
    }

    info('Logger', 'Logger initialized',
        metadata: {'mode': kReleaseMode ? 'release' : 'debug'});
  }

  void setCorrelationId(String? id) {
    _currentCorrelationId = id;
  }

  void debug(String category, String message,
      {Map<String, dynamic>? metadata}) {
    _log(LogLevel.debug, category, message, metadata: metadata);
  }

  void info(String category, String message,
      {Map<String, dynamic>? metadata}) {
    _log(LogLevel.info, category, message, metadata: metadata);
  }

  void warning(String category, String message,
      {Map<String, dynamic>? metadata}) {
    _log(LogLevel.warning, category, message, metadata: metadata);
  }

  void error(String category, String message,
      {Map<String, dynamic>? metadata, Object? exception, StackTrace? stack}) {
    final enrichedMetadata = <String, dynamic>{
      ...?metadata,
      if (exception != null) 'error_type': exception.runtimeType.toString(),
      if (exception != null) 'error_message': exception.toString(),
      if (stack != null) 'stack_trace': stack.toString(),
    };
    _log(LogLevel.error, category, message, metadata: enrichedMetadata);
  }

  void critical(String category, String message,
      {Map<String, dynamic>? metadata, Object? exception, StackTrace? stack}) {
    final enrichedMetadata = <String, dynamic>{
      ...?metadata,
      if (exception != null) 'error_type': exception.runtimeType.toString(),
      if (exception != null) 'error_message': exception.toString(),
      if (stack != null) 'stack_trace': stack.toString(),
    };
    _log(LogLevel.critical, category, message, metadata: enrichedMetadata);
  }

  void _log(LogLevel level, String category, String message,
      {Map<String, dynamic>? metadata}) {
    if (level.index < LogConfig.minimumLevel.index) return;

    // Always sanitize metadata regardless of environment
    final sanitizedMetadata =
        metadata != null ? LogSanitizer.sanitizeMap(metadata) : null;

    final entry = LogEntry(
      level: level,
      category: category,
      message: message,
      metadata: sanitizedMetadata,
      correlationId: _currentCorrelationId,
    );

    for (final sink in _sinks) {
      try {
        sink.write(entry);
      } catch (e) {
        // Avoid recursive logging failures
        if (kDebugMode) {
          debugPrint('LogSink error: $e');
        }
      }
    }
  }
}

/// Abstract sink for log output
abstract class LogSink {
  void write(LogEntry entry);
}

/// Console sink for debug builds only
class ConsoleLogSink extends LogSink {
  @override
  void write(LogEntry entry) {
    // Only output to console in debug mode
    if (kDebugMode) {
      debugPrint(entry.toString());
    }
  }
}

/// Secure remote log sink that sends logs to a monitoring service
/// over HTTPS with certificate pinning
class RemoteLogSink extends LogSink {
  final String endpoint;
  final List<LogEntry> _buffer = [];
  final int _bufferSize;
  Timer? _flushTimer;

  RemoteLogSink({
    required this.endpoint,
    int bufferSize = 50,
    Duration flushInterval = const Duration(seconds: 30),
  }) : _bufferSize = bufferSize {
    _flushTimer = Timer.periodic(flushInterval, (_) => flush());
  }

  @override
  void write(LogEntry entry) {
    _buffer.add(entry);
    if (_buffer.length >= _bufferSize) {
      flush();
    }
  }

  Future<void> flush() async {
    if (_buffer.isEmpty) return;

    final entries = List<LogEntry>.from(_buffer);
    _buffer.clear();

    try {
      // Send to remote logging service over HTTPS
      final client = HttpClient();
      // In production, add certificate pinning here:
      // client.badCertificateCallback = ...

      final request = await client.postUrl(Uri.parse(endpoint));
      request.headers.set('Content-Type', 'application/json');

      final payload = jsonEncode({
        'entries': entries.map((e) => e.toJson()).toList(),
      });

      request.write(payload);
      final response = await request.close();
      await response.drain();
      client.close();
    } catch (e) {
      // Re-buffer on failure (with limit to prevent memory issues)
      if (_buffer.length < _bufferSize * 3) {
        _buffer.insertAll(0, entries);
      }
    }
  }

  void dispose() {
    _flushTimer?.cancel();
    flush();
  }
}

