/// HTTP request/response logger
class HttpLogger {
  static final _logger = AppLogger();
  static const _category = 'HTTP';

  /// Log an outgoing HTTP request
  static void logRequest({
    required String method,
    required String url,
    Map<String, String>? headers,
    dynamic body,
    String? correlationId,
  }) {
    final sanitizedUrl = LogSanitizer.sanitizeUrl(url);
    final sanitizedHeaders = LogSanitizer.sanitizeHeaders(headers);
    final sanitizedBody = LogSanitizer.sanitizeBody(body);

    _logger.info(
      _category,
      '$method $sanitizedUrl',
      metadata: {
        'direction': 'request',
        'method': method,
        'url': sanitizedUrl,
        'headers': sanitizedHeaders,
        'body_preview': sanitizedBody,
        if (correlationId != null) 'correlation_id': correlationId,
      },
    );
  }

  /// Log an HTTP response
  static void logResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, String>? headers,
    dynamic body,
    Duration? duration,
    String? correlationId,
  }) {
    final sanitizedUrl = LogSanitizer.sanitizeUrl(url);
    final sanitizedHeaders = LogSanitizer.sanitizeHeaders(headers);
    final sanitizedBody = LogSanitizer.sanitizeBody(body);

    final level = statusCode >= 500
        ? LogLevel.error
        : statusCode >= 400
            ? LogLevel.warning
            : LogLevel.info;

    _logger._log(
      level,
      _category,
      '$method $sanitizedUrl -> $statusCode',
      metadata: {
        'direction': 'response',
        'method': method,
        'url': sanitizedUrl,
        'status_code': statusCode,
        'headers': sanitizedHeaders,
        'body_preview': sanitizedBody,
        if (duration != null) 'duration_ms': duration.inMilliseconds,
        if (correlationId != null) 'correlation_id': correlationId,
      },
    );
  }

  /// Log an HTTP error
  static void logError({
    required String method,
    required String url,
    required Object error,
    StackTrace? stackTrace,
    String? correlationId,
  }) {
    final sanitizedUrl = LogSanitizer.sanitizeUrl(url);

    _logger.error(
      _category,
      'Request failed: $method $sanitizedUrl',
      metadata: {
        'method': method,
        'url': sanitizedUrl,
        if (correlationId != null) 'correlation_id': correlationId,
      },
      exception: error,
      stack: stackTrace,
    );
  }
}

/// Database operation logger
class DatabaseLogger {
  static final _logger = AppLogger();
  static const _category = 'DATABASE';

  /// Log a database query (never log actual data values in production)
  static void logQuery({
    required String operation,
    required String table,
    Duration? duration,
    int? rowsAffected,
    String? whereClause,
  }) {
    _logger.debug(
      _category,
      '$operation on $table',
      metadata: {
        'operation': operation,
        'table': table,
        if (duration != null) 'duration_ms': duration.inMilliseconds,
        if (rowsAffected != null) 'rows_affected': rowsAffected,
        // Log structure of query but not values
        if (whereClause != null)
          'where_clause': _sanitizeWhereClause(whereClause),
      },
    );
  }

  /// Log a database error
  static void logError({
    required String operation,
    required String table,
    required Object error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      _category,
      'Database error: $operation on $table',
      metadata: {
        'operation': operation,
        'table': table,
      },
      exception: error,
      stack: stackTrace,
    );
  }

  /// Log database migration
  static void logMigration({
    required int fromVersion,
    required int toVersion,
    required bool success,
    Duration? duration,
  }) {
    final level = success ? LogLevel.info : LogLevel.error;
    _logger._log(
      level,
      _category,
      'Migration v$fromVersion -> v$toVersion: ${success ? "success" : "failed"}',
      metadata: {
        'from_version': fromVersion,
        'to_version': toVersion,
        'success': success,
        if (duration != null) 'duration_ms': duration.inMilliseconds,
      },
    );
  }

  /// Remove literal values from WHERE clauses, keep structure
  static String _sanitizeWhereClause(String clause) {
    // Replace string literals
    var sanitized = clause.replaceAll(RegExp(r"'[^']*'"), "'[REDACTED]'");
    // Replace numeric values after = or comparison operators
    sanitized = sanitized.replaceAll(
        RegExp(r'(=|>|<|>=|<=|!=)\s*\d+'), r'$1 [REDACTED]');
    return sanitized;
  }
}

/// Authentication flow logger - extra careful with sensitive data
class AuthLogger {
  static final _logger = AppLogger();
  static const _category = 'AUTH';

  /// Log a login attempt (NEVER log credentials)
  static void logLoginAttempt({
    required String method,
    String? email,
  }) {
    _logger.info(
      _category,
      'Login attempt via $method',
      metadata: {
        'method': method,
        // Only log sanitized email for user identification
        if (email != null) 'user_hint': LogSanitizer.sanitizeEmail(email),
      },
    );
  }

  /// Log login result
  static void logLoginResult({
    required bool success,
    required String method,
    String? email,
    String? failureReason,
  }) {
    final level = success ? LogLevel.info : LogLevel.warning;
    _logger._log(
      level,
      _category,
      'Login ${success ? "successful" : "failed"} via $method',
      metadata: {
        'success': success,
        'method': method,
        if (email != null) 'user_hint': LogSanitizer.sanitizeEmail(email),
        // Log generic failure reason, never specific credential details
        if (failureReason != null) 'failure_reason': failureReason,
      },
    );
  }

  /// Log token refresh (NEVER log token values)
  static void logTokenRefresh({
    required bool success,
    String? failureReason,
  }) {
    final level = success ? LogLevel.debug : LogLevel.warning;
    _logger._log(
      level,
      _category,
      'Token refresh ${success ? "successful" : "failed"}',
      metadata: {
        'success': success,
        if (failureReason != null) 'failure_reason': failureReason,
      },
    );
  }

  /// Log logout
  static void logLogout({
    required String reason,
    String? userId,
  }) {
    _logger.info(
      _category,
      'User logged out',
      metadata: {
        'reason': reason,
        if (userId != null) 'user_hint': LogSanitizer.sanitizeUserId(userId),
      },
    );
  }

  /// Log password reset request (NEVER log passwords or reset tokens)
  static void logPasswordResetRequest({
    String? email,
    required bool success,
  }) {
    _logger.info(
      _category,
      'Password reset requested',
      metadata: {
        'success': success,
        if (email != null) 'user_hint': LogSanitizer.sanitizeEmail(email),
      },
    );
  }

  /// Log MFA events
  static void logMfaEvent({
    required String event,
    required String method,
    required bool success,
  }) {
    _logger.info(
      _category,
      'MFA $event via $method: ${success ? "success" : "failed"}',
      metadata: {
        'event': event,
        'method': method,
        'success': success,
        // NEVER log MFA codes, backup codes, or TOTP secrets
      },
    );
  }
}

