/// Performance logger
class PerformanceLogger {
  static final _logger = AppLogger();
  static const _category = 'PERFORMANCE';

  /// Log a timed operation
  static Future<T> logOperation<T>({
    required String name,
    required Future<T> Function() operation,
    Map<String, dynamic>? metadata,
  }) async {
    final stopwatch = Stopwatch()..start();
    try {
      final result = await operation();
      stopwatch.stop();
      _logger.debug(
        _category,
        '$name completed in ${stopwatch.elapsedMilliseconds}ms',
        metadata: {
          'operation': name,
          'duration_ms': stopwatch.elapsedMilliseconds,
          'success': true,
          if (metadata != null) ...LogSanitizer.sanitizeMap(metadata),
        },
      );
      return result;
    } catch (e, stack) {
      stopwatch.stop();
      _logger.error(
        _category,
        '$name failed after ${stopwatch.elapsedMilliseconds}ms',
        metadata: {
          'operation': name,
          'duration_ms': stopwatch.elapsedMilliseconds,
          'success': false,
          if (metadata != null) ...LogSanitizer.sanitizeMap(metadata),
        },
        exception: e,
        stack: stack,
      );
      rethrow;
    }
  }

  /// Log slow operations that exceed a threshold
  static void logSlowOperation({
    required String name,
    required Duration duration,
    required Duration threshold,
  }) {
    if (duration > threshold) {
      _logger.warning(
        _category,
        'Slow operation: $name took ${duration.inMilliseconds}ms '
            '(threshold: ${threshold.inMilliseconds}ms)',
        metadata: {
          'operation': name,
          'duration_ms': duration.inMilliseconds,
          'threshold_ms': threshold.inMilliseconds,
        },
      );
    }
  }
}

