void initializeLogging() {
  final logger = AppLogger();

  if (kReleaseMode) {
    // In production, send logs to a secure remote endpoint
    logger.initialize(
      sinks: [
        RemoteLogSink(
          endpoint: 'https://logs.yourapp.com/api/v1/ingest',
          bufferSize: 100,
          flushInterval: const Duration(seconds: 60),
        ),
      ],
    );
  } else {
    // In debug mode, console output is sufficient
    logger.initialize();
  }
}

/// Example demonstrating secure logging patterns
void exampleUsage() {
  // HTTP logging - sensitive data is automatically redacted
  HttpLogger.logRequest(
    method: 'POST',
    url: 'https://api.example.com/auth/login?redirect=home',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIs...', // Will be REDACTED
    },
    body: {
      'email': 'user@example.com',
      'password': 'supersecret123', // Will be REDACTED
    },
  );

  // Auth logging - credentials are never logged
  AuthLogger.logLoginAttempt(
    method: 'email_password',
    email: 'user@example.com', // Will be sanitized to "u***r@example.com"
  );

  AuthLogger.logLoginResult(
    success: false,
    method: 'email_password',
    email: 'user@example.com',
    failureReason: 'invalid_credentials', // Generic reason, not specific
  );

  // Database logging - values are not logged
  DatabaseLogger.logQuery(
    operation: 'SELECT',
    table: 'users',
    duration: const Duration(milliseconds: 45),
    rowsAffected: 1,
    whereClause: "email = 'user@example.com'", // Values will be redacted
  );

  // User interaction logging
  InteractionLogger.logScreenView(screenName: 'ProfileScreen');
  InteractionLogger.logAction(action: 'tap', target: 'save_button');
}